import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import AiAssistant from './components/AiAssistant';
// Import all your page components
import AuthorityPage from './pages/Authority';
import BinPage from './pages/Bin';
import DriverPage from './pages/Driver';
import UserPage from './pages/User';
import VehiclePage from './pages/Vehicle';

function App() {
      const appStyles = {
        minHeight: '100vh',
        background: '#f8f9fa',
        fontFamily: "'Segoe UI', 'Arial', sans-serif",
      };

  const containerStyles = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '20px',
    minHeight: 'calc(100vh - 80px)',
  };

      const welcomeStyles = {
        textAlign: 'center',
        color: '#333',
        fontSize: '2.5rem',
        fontWeight: '700',
        marginTop: '40px',
        background: 'rgba(255, 255, 255, 0.95)',
        backdropFilter: 'blur(10px)',
        padding: '50px',
        borderRadius: '24px',
        border: 'none',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3), 0 10px 30px rgba(0,0,0,0.2)',
        animation: 'fadeIn 0.6s ease-in',
      };

  return (
    <div style={appStyles}>
      <Router>
        <Navbar />
        <div style={containerStyles}>
          <Routes>
            {/* Default landing page */}
                <Route path="/" element={
                  <div style={welcomeStyles}>
                    <h1>Waste Management System</h1>
                    <p style={{ fontSize: '1.1rem', marginTop: '20px', color: '#666' }}>
                      Database Management System for Waste Collection Operations
                    </p>
                    <style>{`
                      @keyframes fadeIn {
                        from { opacity: 0; transform: translateY(20px); }
                        to { opacity: 1; transform: translateY(0); }
                      }
                      @keyframes float {
                        0%, 100% { transform: translateY(0px); }
                        50% { transform: translateY(-10px); }
                      }
                      .feature-card {
                        animation: fadeIn 0.6s ease-in, float 3s ease-in-out infinite;
                        animation-fill-mode: both;
                      }
                      .feature-card:nth-child(1) { animation-delay: 0s, 0s; }
                      .feature-card:nth-child(2) { animation-delay: 0.1s, 0.5s; }
                      .feature-card:nth-child(3) { animation-delay: 0.2s, 1s; }
                      .feature-card:nth-child(4) { animation-delay: 0.3s, 1.5s; }
                      .feature-card:nth-child(5) { animation-delay: 0.4s, 2s; }
                      .feature-card:hover {
                        transform: translateY(-8px) scale(1.02);
                        box-shadow: 0 25px 50px rgba(0,0,0,0.25) !important;
                      }
                    `}</style>
                    <div style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                      gap: '30px',
                      marginTop: '40px'
                    }}>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(102, 126, 234, 0.3)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>👥 Authority</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Manage waste management authorities and their organizational hierarchy</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(245, 87, 108, 0.3)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>🚗 Driver</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Handle driver information, assignments, and workforce management</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(250, 112, 154, 0.3)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>🚛 Vehicle</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Track and manage waste collection vehicles and fleet operations</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(79, 172, 254, 0.3)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>🗂️ Bin</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Monitor waste bins, their locations, and collection schedules</p>
                      </div>
                      <div className="feature-card" style={{ 
                        background: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)',
                        padding: '30px', 
                        borderRadius: '20px',
                        border: 'none',
                        boxShadow: '0 10px 30px rgba(67, 233, 123, 0.3)',
                        transition: 'all 0.3s ease',
                        cursor: 'pointer',
                        color: 'white'
                      }}>
                        <h4 style={{ margin: '0 0 15px 0', fontSize: '1.5rem', color: '#ffffff', fontWeight: '700' }}>👤 User</h4>
                        <p style={{ margin: '0', fontSize: '1rem', color: 'rgba(255,255,255,0.9)', lineHeight: '1.6' }}>Manage system users, their profiles, and access permissions</p>
                      </div>
                    </div>
                  </div>
                } />

            {/* Routes for each entity management page */}
            <Route path="/authority" element={<AuthorityPage />} />
            <Route path="/bin" element={<BinPage />} />
            <Route path="/driver" element={<DriverPage />} />
            <Route path="/user" element={<UserPage />} />
            <Route path="/vehicle" element={<VehiclePage />} />
          </Routes>
        </div>
        <AiAssistant />
      </Router>
    </div>
  );
}

export default App;
